  requires s[i] == s[j]
  ensures multiset(s)[s[i]] >= 2
{
  var left := s[..i + 1];
  var right := s[i + 1..];
  assert s == left + right;
  assert left[i] == s[i];
  assert right[j - i - 1] == s[j];
